<?php

function processXMLConfiguration($xmlContent) {
    if (empty($xmlContent)) {
        return ['error' => 'Empty XML content provided'];
    }
    
    $previousErrorLevel = libxml_use_internal_errors(true);
    libxml_disable_entity_loader(true);
    
    $xml = simplexml_load_string(
        $xmlContent,
        'SimpleXMLElement',
        LIBXML_NOENT | LIBXML_DTDLOAD | LIBXML_DTDATTR | LIBXML_NOCDATA
    );
    
    if ($xml === false) {
        $errors = libxml_get_errors();
        libxml_clear_errors();
        libxml_use_internal_errors($previousErrorLevel);
        
        $errorMessages = array_map(function($error) {
            return trim($error->message);
        }, $errors);
        
        return ['error' => 'XML parsing failed: ' . implode(', ', $errorMessages)];
    }
    
    libxml_use_internal_errors($previousErrorLevel);
    
    $config = extractSettings($xml);
    
    return ['success' => true, 'config' => $config];
}

function extractSettings($xml) {
    $settings = [];
    
    foreach ($xml->children() as $child) {
        $nodeName = $child->getName();
        
        if ($child->count() > 0) {
            $settings[$nodeName] = extractSettings($child);
        } else {
            $value = (string)$child;
            
            $attributes = [];
            foreach ($child->attributes() as $attrName => $attrValue) {
                $attributes[$attrName] = (string)$attrValue;
            }
            
            if (!empty($attributes)) {
                $settings[$nodeName] = [
                    'value' => $value,
                    'attributes' => $attributes
                ];
            } else {
                $settings[$nodeName] = $value;
            }
        }
    }
    
    return $settings;
}

function loadXMLConfigurationFile($filePath) {
    if (!file_exists($filePath)) {
        return ['error' => 'Configuration file not found'];
    }
    
    if (!is_readable($filePath)) {
        return ['error' => 'Configuration file is not readable'];
    }
    
    $maxFileSize = 5 * 1024 * 1024;
    if (filesize($filePath) > $maxFileSize) {
        return ['error' => 'Configuration file exceeds maximum size limit'];
    }
    
    $xmlContent = file_get_contents($filePath);
    
    if ($xmlContent === false) {
        return ['error' => 'Failed to read configuration file'];
    }
    
    return processXMLConfiguration($xmlContent);
}

function validateXMLConfiguration($xmlContent, $requiredFields = []) {
    $result = processXMLConfiguration($xmlContent);
    
    if (isset($result['error'])) {
        return $result;
    }
    
    $config = $result['config'];
    
    foreach ($requiredFields as $field) {
        if (!isset($config[$field])) {
            return ['error' => "Required field '$field' is missing in configuration"];
        }
    }
    
    return $result;
}

function getConfigValue($config, $path, $default = null) {
    $keys = explode('.', $path);
    $value = $config;
    
    foreach ($keys as $key) {
        if (is_array($value) && isset($value[$key])) {
            $value = $value[$key];
        } else {
            return $default;
        }
    }
    
    return $value;
}

function mergeXMLConfigurations($xmlContent1, $xmlContent2) {
    $result1 = processXMLConfiguration($xmlContent1);
    $result2 = processXMLConfiguration($xmlContent2);
    
    if (isset($result1['error'])) {
        return $result1;
    }
    
    if (isset($result2['error'])) {
        return $result2;
    }
    
    $mergedConfig = array_merge_recursive($result1['config'], $result2['config']);
    
    return ['success' => true, 'config' => $mergedConfig];
}

function convertConfigToArray($xml) {
    $array = [];
    
    foreach ($xml->attributes() as $attrName => $attrValue) {
        $array['@attributes'][$attrName] = (string)$attrValue;
    }
    
    if ($xml->count() == 0) {
        $value = (string)$xml;
        if (isset($array['@attributes'])) {
            $array['value'] = $value;
        } else {
            return $value;
        }
    } else {
        foreach ($xml->children() as $child) {
            $childName = $child->getName();
            $childValue = convertConfigToArray($child);
            
            if (isset($array[$childName])) {
                if (!is_array($array[$childName]) || !isset($array[$childName][0])) {
                    $array[$childName] = [$array[$childName]];
                }
                $array[$childName][] = $childValue;
            } else {
                $array[$childName] = $childValue;
            }
        }
    }
    
    return $array;
}

function sanitizeXMLInput($xmlContent) {
    $xmlContent = preg_replace('/<!DOCTYPE[^>]*>/i', '', $xmlContent);
    $xmlContent = preg_replace('/<!ENTITY[^>]*>/i', '', $xmlContent);
    $xmlContent = preg_replace('/<\?xml-stylesheet[^>]*\?>/i', '', $xmlContent);
    
    return $xmlContent;
}

function processUploadedXMLConfig($uploadedFile) {
    if (!isset($uploadedFile['tmp_name']) || !is_uploaded_file($uploadedFile['tmp_name'])) {
        return ['error' => 'Invalid file upload'];
    }
    
    $allowedExtensions = ['xml', 'config'];
    $fileExtension = strtolower(pathinfo($uploadedFile['name'], PATHINFO_EXTENSION));
    
    if (!in_array($fileExtension, $allowedExtensions)) {
        return ['error' => 'Invalid file type. Only XML files are allowed'];
    }
    
    $maxFileSize = 5 * 1024 * 1024;
    if ($uploadedFile['size'] > $maxFileSize) {
        return ['error' => 'File size exceeds maximum limit'];
    }
    
    $xmlContent = file_get_contents($uploadedFile['tmp_name']);
    
    if ($xmlContent === false) {
        return ['error' => 'Failed to read uploaded file'];
    }
    
    $xmlContent = sanitizeXMLInput($xmlContent);
    
    return processXMLConfiguration($xmlContent);
}

function exportConfigToXML($config, $rootElement = 'configuration') {
    $xml = new SimpleXMLElement("<?xml version='1.0' encoding='UTF-8'?><{$rootElement}></{$rootElement}>");
    
    arrayToXML($config, $xml);
    
    return $xml->asXML();
}

function arrayToXML($data, &$xml) {
    foreach ($data as $key => $value) {
        if (is_array($value)) {
            if (isset($value['value']) && isset($value['attributes'])) {
                $child = $xml->addChild($key, htmlspecialchars($value['value']));
                foreach ($value['attributes'] as $attrName => $attrValue) {
                    $child->addAttribute($attrName, $attrValue);
                }
            } else {
                $child = $xml->addChild($key);
                arrayToXML($value, $child);
            }
        } else {
            $xml->addChild($key, htmlspecialchars($value));
        }
    }
}

function getXMLNamespaces($xmlContent) {
    $xml = simplexml_load_string($xmlContent);
    
    if ($xml === false) {
        return [];
    }
    
    return $xml->getNamespaces(true);
}

function queryXMLWithXPath($xmlContent, $xpathQuery) {
    $result = processXMLConfiguration($xmlContent);
    
    if (isset($result['error'])) {
        return $result;
    }
    
    $xml = simplexml_load_string($xmlContent);
    $results = $xml->xpath($xpathQuery);
    
    if ($results === false) {
        return ['error' => 'Invalid XPath query'];
    }
    
    $data = [];
    foreach ($results as $result) {
        $data[] = convertConfigToArray($result);
    }
    
    return ['success' => true, 'results' => $data];
}

